class _Node:
    __slots__ = ("val", "left", "right")
    def __init__(self, val):
        self.val = val
        self.left = None
        self.right = None


def _build(values):
    if not values or values[0] is None:
        return None
    root = _Node(values[0])
    queue = [root]
    i = 1
    while queue and i < len(values):
        node = queue.pop(0)
        if i < len(values):
            v = values[i]
            i += 1
            if v is not None:
                node.left = _Node(v)
                queue.append(node.left)
        if i < len(values):
            v = values[i]
            i += 1
            if v is not None:
                node.right = _Node(v)
                queue.append(node.right)
    return root


def _depth(node):
    if node is None:
        return 0
    return 1 + max(_depth(node.left), _depth(node.right))


def max_depth(values):
    return _depth(_build(values))
